-- ============================================================
-- HISTORY GRAPH - Philosophy-History Force Graph Tables
-- 3D Interactive visualization of 2,600 years of philosophical thought
-- ============================================================

-- Graph Nodes: Philosophers, Events, Concepts, Eras, Content, Battles
CREATE TABLE IF NOT EXISTS graph_nodes (
  id TEXT PRIMARY KEY,
  label TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN (
    'philosopher', 'event', 'concept', 'era', 'content', 'battle'
  )),
  tradition TEXT NOT NULL DEFAULT 'western' CHECK (tradition IN (
    'western', 'chinese', 'indian', 'islamic', 'universal'
  )),
  era TEXT,
  years TEXT,
  year_numeric INTEGER,        -- negative for BC, positive for AD
  weight TEXT NOT NULL DEFAULT 'standard' CHECK (weight IN (
    'maximum', 'high', 'standard', 'minor'
  )),
  description TEXT NOT NULL,
  is_seed BOOLEAN DEFAULT false,
  active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Graph Edges: Relationships between nodes
CREATE TABLE IF NOT EXISTS graph_edges (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  source_id TEXT NOT NULL REFERENCES graph_nodes(id),
  target_id TEXT NOT NULL REFERENCES graph_nodes(id),
  relation TEXT NOT NULL CHECK (relation IN (
    'influenced', 'caused', 'responded_to', 'derived_from',
    'applied_in', 'fulfills_legacy_of', 'opposes_legacy_of',
    'transmitted', 'synthesized', 'contradicted'
  )),
  battle_dimension TEXT CHECK (battle_dimension IN (
    'reality_vs_mysticism', 'reason_vs_faith',
    'individualism_vs_collectivism', 'freedom_vs_coercion',
    'value_creation_vs_nihilism', 'free_market_vs_planning',
    'beauty_vs_chaos', 'good_vs_evil'
  )),
  label TEXT NOT NULL,
  weight FLOAT DEFAULT 1.0,
  analysis_id TEXT,
  is_seed BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(source_id, target_id, relation)
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_graph_edges_source ON graph_edges(source_id);
CREATE INDEX IF NOT EXISTS idx_graph_edges_target ON graph_edges(target_id);
CREATE INDEX IF NOT EXISTS idx_graph_nodes_year ON graph_nodes(year_numeric);
CREATE INDEX IF NOT EXISTS idx_graph_nodes_tradition ON graph_nodes(tradition);
CREATE INDEX IF NOT EXISTS idx_graph_nodes_type ON graph_nodes(type);
CREATE INDEX IF NOT EXISTS idx_graph_nodes_active ON graph_nodes(active);

-- ============================================================
-- SEED DATA: ERAS
-- ============================================================

INSERT INTO graph_nodes (id, label, type, tradition, era, years, year_numeric, weight, description, is_seed) VALUES
('era_axial_age', 'Axial Age', 'era', 'universal', 'Ancient', '800–200 BC', -500, 'maximum', 'The philosopher Karl Jaspers identified this as the pivotal period when the great intellectual traditions of humanity emerged simultaneously and independently — Greek philosophy, Chinese Confucianism and Taoism, Indian Buddhism and Upanishadic thought, and Hebrew monotheism. Human consciousness turned reflective for the first time, questioning the foundations of existence, ethics, and reality.', true),
('era_ancient_greece', 'Ancient Greece', 'era', 'western', 'Ancient', '600–300 BC', -450, 'maximum', 'The birthplace of Western philosophy, democracy, and systematic rational inquiry. Greek thinkers established the foundational questions of metaphysics, ethics, politics, and aesthetics that all subsequent Western philosophy has engaged with.', true),
('era_hellenistic', 'Hellenistic Period', 'era', 'western', 'Ancient', '323–31 BC', -175, 'high', 'The era following Alexander''s conquests when Greek culture spread across the known world. Philosophy became cosmopolitan — Stoicism, Epicureanism, and Skepticism addressed the individual rather than the citizen of a specific polis. East and West began their first systematic intellectual exchange.', true),
('era_roman', 'Roman Empire', 'era', 'western', 'Ancient', '27 BC–476 AD', 200, 'high', 'The political and cultural heir to Greece. Rome synthesized Greek philosophy with practical governance, law, and Stoic ethics. Its collapse reshaped the intellectual map of Europe for a millennium.', true),
('era_classical_china', 'Classical China', 'era', 'chinese', 'Ancient', '600–200 BC', -400, 'maximum', 'The era of the Hundred Schools of Thought — Confucianism, Taoism, Legalism, Mohism, and others competing to define the proper order of society and the cosmos. The most concentrated period of philosophical creativity in Chinese history.', true),
('era_classical_india', 'Classical India', 'era', 'indian', 'Ancient', '600–200 BC', -400, 'maximum', 'The era of the Upanishads, the Buddha, the Jains, and the Charvakas — competing visions of reality, consciousness, liberation, and the self. Indian philosophy developed its most distinctive questions about the nature of mind, reality, and ethical action independently of Greek thought.', true),
('era_islamic_golden_age', 'Islamic Golden Age', 'era', 'islamic', 'Medieval', '750–1258 AD', 1000, 'maximum', 'The period of extraordinary intellectual flourishing in the Islamic world. Muslim philosophers preserved, translated, and extended Greek philosophical works — particularly Aristotle — while developing original contributions in mathematics, astronomy, medicine, and philosophy. Without this era, Aristotle would have been lost to the West.', true),
('era_middle_ages', 'Middle Ages', 'era', 'western', 'Medieval', '500–1400 AD', 900, 'high', 'A millennium in which theological authority dominated Western intellectual life. Philosophy survived within religious institutions, engaging the tension between reason and faith that would define the era''s greatest minds.', true),
('era_renaissance', 'Renaissance', 'era', 'western', 'Early Modern', '1400–1600', 1500, 'high', 'The rebirth of classical learning. Thinkers returned to Greek and Roman sources, placing human reason and individual achievement at the center of intellectual life. The printing press transformed the speed of intellectual exchange.', true),
('era_enlightenment', 'Enlightenment', 'era', 'western', 'Modern', '1650–1800', 1725, 'maximum', 'The age of reason — systematic application of rational inquiry to science, politics, ethics, and religion. Produced the intellectual foundations of liberalism, democracy, and modern science. The most consequential intellectual era of the modern world.', true),
('era_19th_century', '19th Century', 'era', 'universal', 'Modern', '1800–1900', 1850, 'high', 'The century of ideological crystallization. Liberalism, conservatism, socialism, nationalism, and anarchism emerged as distinct political philosophies. Darwin transformed biology and challenged teleological thinking. The conditions for the 20th century''s catastrophes were laid.', true),
('era_20th_century', '20th Century', 'era', 'universal', 'Contemporary', '1900–2000', 1950, 'maximum', 'The most violent and transformative century in recorded history. Totalitarianism, two world wars, decolonization, the Cold War, and the information revolution all compressed into a single lifetime. Philosophy was forced to confront unprecedented evil and unprecedented technological power simultaneously.', true),
('era_contemporary', 'Contemporary', 'era', 'universal', 'Contemporary', '2000–present', 2013, 'standard', 'The digital age — characterized by the collapse of geographic limits on information, the rise of artificial intelligence, and the collision of global capitalism with authoritarian resurgence and identity politics. The Axial Age questions return in new technological forms.', true)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- SEED DATA: PHILOSOPHERS — ALL TRADITIONS
-- ============================================================

INSERT INTO graph_nodes (id, label, type, tradition, era, years, year_numeric, weight, description, is_seed) VALUES
-- PRE-SOCRATICS (Western trunk)
('philosopher_thales', 'Thales', 'philosopher', 'western', 'Ancient Greece', '624–546 BC', -585, 'high', 'The first philosopher in the Western tradition. Asked what the world is fundamentally made of and answered: water. The question matters more than the answer — he initiated the project of explaining reality through natural principles rather than mythological narratives. The birth of rational inquiry.', true),
('philosopher_heraclitus', 'Heraclitus', 'philosopher', 'western', 'Ancient Greece', '535–475 BC', -505, 'high', 'The philosopher of flux and the Logos. "You cannot step into the same river twice." Reality is perpetual change governed by a rational principle (Logos) underlying apparent contradictions. His opposition between the rational order and those who sleepwalk through life anticipates the reason vs. mysticism battle across millennia.', true),
('philosopher_parmenides', 'Parmenides', 'philosopher', 'western', 'Ancient Greece', '515–450 BC', -480, 'high', 'The philosopher of Being. Argued that reality is one, unchanging, and eternal — and that change and multiplicity are illusions of the senses. His rationalist monism directly challenged Heraclitean flux and forced all subsequent philosophy to address the problem of the One and the Many.', true),
('philosopher_pythagoras', 'Pythagoras', 'philosopher', 'western', 'Ancient Greece', '570–495 BC', -530, 'standard', 'Mathematician and mystic — a paradoxical combination. His discovery that mathematical ratios govern musical harmony suggested the cosmos is fundamentally mathematical. But he surrounded this insight with religious mysticism about the transmigration of souls, making him simultaneously a precursor of scientific rationalism and of Platonic other-worldliness.', true),
('philosopher_democritus', 'Democritus', 'philosopher', 'western', 'Ancient Greece', '460–370 BC', -415, 'high', 'The founder of atomism. Proposed that reality consists entirely of indivisible particles (atoms) moving through void — with no purpose, no soul, no divine intervention. The first materialist philosophy. His vision anticipates modern physics and stands as the most radical assertion of objective reality against mysticism in ancient thought.', true),

-- CLASSICAL GREEK
('philosopher_socrates', 'Socrates', 'philosopher', 'western', 'Ancient Greece', '470–399 BC', -435, 'maximum', 'The father of Western moral philosophy. Turned philosophy from cosmology to ethics — from "what is the world?" to "how should I live?". His method of relentless questioning (elenchus) exposed hidden assumptions. Executed for impiety and corrupting youth — the first philosopher martyred for ideas.', true),
('philosopher_plato', 'Plato', 'philosopher', 'western', 'Ancient Greece', '428–348 BC', -388, 'maximum', 'Student of Socrates, teacher of Aristotle. Founded the Academy. His theory of Forms — abstract ideals more real than physical things — established the foundational split between appearance and reality, between this world and a higher one, that runs through all Western thought. Whitehead called all Western philosophy "footnotes to Plato."', true),
('philosopher_aristotle', 'Aristotle', 'philosopher', 'western', 'Ancient Greece', '384–322 BC', -354, 'maximum', 'The philosopher. Rejected Platonic idealism and grounded philosophy in observable reality. Founded formal logic, biology, physics, ethics, politics, rhetoric, and aesthetics as systematic disciplines. His metaphysical realism — reality exists independent of consciousness — became the foundation Aquinas built on, and the tradition Ayn Rand identified as her primary philosophical ancestor.', true),

-- HELLENISTIC
('philosopher_epicurus', 'Epicurus', 'philosopher', 'western', 'Hellenistic', '341–270 BC', -305, 'standard', 'Founded Epicureanism — the pursuit of tranquil pleasure (ataraxia) through friendship, philosophical reflection, and freedom from fear of death and gods. Often misrepresented as hedonism; actually advocated modest pleasures and withdrawal from political life as the path to happiness.', true),
('philosopher_zeno_stoic', 'Zeno of Citium', 'philosopher', 'western', 'Hellenistic', '334–262 BC', -298, 'high', 'Founder of Stoicism. Argued that virtue is the only good and that external circumstances — wealth, health, reputation — are indifferent. The rational person accepts what cannot be changed and focuses on what is within their control: their own judgments and responses. Stoicism became the dominant philosophy of the Roman Empire.', true),
('philosopher_pyrrho', 'Pyrrho', 'philosopher', 'western', 'Hellenistic', '360–270 BC', -315, 'standard', 'Founder of ancient Skepticism. Argued that we cannot know anything with certainty — our senses and reason are equally unreliable. The appropriate response is suspension of judgment (epoché), which produces tranquility. His radical skepticism influenced all subsequent epistemology.', true),

-- ROMAN
('philosopher_cicero', 'Cicero', 'philosopher', 'western', 'Roman Empire', '106–43 BC', -75, 'high', 'Rome''s greatest philosopher and orator. Translated Greek philosophical concepts into Latin, making them accessible to Roman culture. His natural law theory — that justice is grounded in reason and universal to all humans — became the foundation of Roman law and, through it, Western legal tradition.', true),
('philosopher_marcus_aurelius', 'Marcus Aurelius', 'philosopher', 'western', 'Roman Empire', '121–180 AD', 150, 'high', 'Roman Emperor and Stoic philosopher. His Meditations — private notes never intended for publication — remain the definitive statement of Stoic practice under real conditions of power. Accept what you cannot control. Do your duty. Reason clearly. His life demonstrated that philosophy is not merely theoretical.', true),
('philosopher_plotinus', 'Plotinus', 'philosopher', 'western', 'Roman Empire', '204–270 AD', 237, 'standard', 'Founder of Neoplatonism. Developed Plato''s thought into a comprehensive mystical system — reality emanates from "the One" through Intellect and Soul to matter. His synthesis of Greek philosophy and mystical experience profoundly influenced both Christian and Islamic theology.', true),

-- CHINESE TRUNK
('philosopher_laozi', 'Laozi', 'philosopher', 'chinese', 'Classical China', '6th century BC', -550, 'maximum', 'Legendary author of the Tao Te Ching and founder of Taoism. The Tao — the Way — is the underlying principle of reality that cannot be named or grasped conceptually, only lived in harmony with. Laozi''s philosophy stands in fundamental opposition to both Confucian social engineering and Western rationalism: not reason but wu wei (non-action, effortless harmony) is the highest wisdom.', true),
('philosopher_confucius', 'Confucius', 'philosopher', 'chinese', 'Classical China', '551–479 BC', -510, 'maximum', 'The most influential philosopher in Chinese history. His system of social ethics — grounded in ren (benevolence), li (ritual propriety), and the cultivation of virtue through proper relationships — shaped Chinese civilization for 2,500 years. His focus on social harmony and hierarchical relationships stands in productive tension with Western individualism.', true),
('philosopher_mozi', 'Mozi', 'philosopher', 'chinese', 'Classical China', '470–391 BC', -430, 'standard', 'Founder of Mohism — the great rival to Confucianism in classical China. Advocated universal love (jian ai) rather than Confucian graded love, utilitarian calculation rather than ritual, and meritocracy rather than hereditary authority. His utilitarian ethics anticipates Bentham by 2,000 years.', true),
('philosopher_zhuangzi', 'Zhuangzi', 'philosopher', 'chinese', 'Classical China', '369–286 BC', -328, 'high', 'The great literary genius of Taoism. Where Laozi was aphoristic, Zhuangzi was playful, paradoxical, and narrative. His philosophy of radical perspectivism — there is no fixed viewpoint from which to judge reality — challenges all dogmatic systems, including Confucian social certainty and Mohist utilitarian calculation.', true),
('philosopher_mencius', 'Mencius', 'philosopher', 'chinese', 'Classical China', '372–289 BC', -330, 'high', 'The second Confucian sage. Argued that human nature is fundamentally good — moral cultivation recovers our innate goodness rather than imposing external norms. His doctrine of the right to rebel against unjust rulers made him politically dangerous to authoritarian regimes across Chinese history.', true),
('philosopher_han_fei', 'Han Fei', 'philosopher', 'chinese', 'Classical China', '280–233 BC', -256, 'high', 'The greatest philosopher of Legalism. Argued that human nature is fundamentally selfish, making virtue ethics futile — only clear laws, strict enforcement, and calculated rewards and punishments can produce social order. His political realism anticipates Machiavelli by 1,700 years and directly inspired the Qin Dynasty''s unification of China.', true),

-- INDIAN TRUNK
('philosopher_upanishads', 'Upanishadic Sages', 'philosopher', 'indian', 'Classical India', '800–200 BC', -500, 'maximum', 'The anonymous sages whose dialogues constitute the Upanishads — the philosophical core of Hinduism. Their central discovery: Atman (the individual self) is identical to Brahman (the universal consciousness underlying all reality). This non-dualist metaphysics is the most radical assertion of the primacy of consciousness over matter in the history of philosophy.', true),
('philosopher_buddha', 'Siddhartha Gautama', 'philosopher', 'indian', 'Classical India', '563–483 BC', -523, 'maximum', 'The Buddha — the Awakened One. Rejected both the Upanishadic self (Atman) and materialist no-self atomism, proposing anatta (no permanent self) and dependent origination (all phenomena arise in dependence on conditions). His Four Noble Truths and Eightfold Path constitute the most psychologically sophisticated ethical system of the ancient world.', true),
('philosopher_mahavira', 'Mahavira', 'philosopher', 'indian', 'Classical India', '599–527 BC', -563, 'standard', 'The 24th Tirthankara of Jainism. Developed the most rigorous philosophy of non-violence (ahimsa) in history — extending ethical consideration to all living beings including insects. His doctrine of anekantavada (many-sidedness of truth) — that all propositions are partially true from some perspective — anticipates modern pluralism.', true),
('philosopher_nagarjuna', 'Nagarjuna', 'philosopher', 'indian', 'Classical India', '150–250 AD', 200, 'high', 'The founder of Madhyamaka Buddhism — the philosophy of the Middle Way between existence and non-existence. His concept of sunyata (emptiness) — that all phenomena lack inherent existence — is the most rigorous philosophical development of the Buddha''s anatta doctrine. Profoundly influenced Tibetan Buddhism and East Asian thought.', true),
('philosopher_shankara', 'Adi Shankara', 'philosopher', 'indian', 'Medieval', '788–820 AD', 804, 'high', 'The philosopher who revived Advaita Vedanta — the non-dualist reading of the Upanishads. Against Buddhist no-self, Shankara argued that Brahman (universal consciousness) is the only reality; the apparent multiplicity of the world is maya (illusion). His synthesis defined mainstream Hindu philosophy for a millennium.', true),
('philosopher_gandhi', 'Mahatma Gandhi', 'philosopher', 'indian', 'Contemporary', '1869–1948', 1909, 'maximum', 'The philosopher-activist who transformed Indian ethical thought into political practice. His satyagraha (truth-force) — non-violent resistance to coercion — synthesized Hindu ahimsa, Jain anekantavada, Tolstoy''s anarchism, and Thoreau''s civil disobedience into a revolutionary political method. His influence on civil rights movements worldwide makes him the most politically consequential philosopher of the 20th century alongside Marx.', true),

-- ISLAMIC TRUNK
('philosopher_al_kindi', 'Al-Kindi', 'philosopher', 'islamic', 'Islamic Golden Age', '801–873 AD', 837, 'standard', 'The first philosopher in the Arabic tradition. Initiated the project of reconciling Greek philosophy — particularly Aristotle and Neoplatonism — with Islamic theology. Argued that reason and revelation are complementary paths to truth. His translations and commentaries made Greek thought available to the Islamic world for the first time.', true),
('philosopher_al_farabi', 'Al-Farabi', 'philosopher', 'islamic', 'Islamic Golden Age', '872–950 AD', 911, 'high', 'The Second Teacher (after Aristotle). Developed the most comprehensive synthesis of Aristotelian philosophy and Islamic thought. His political philosophy — the virtuous city governed by a philosopher-prophet — was the Islamic world''s answer to Plato''s Republic. Without Al-Farabi, Avicenna and Averroes are impossible.', true),
('philosopher_avicenna', 'Avicenna (Ibn Sina)', 'philosopher', 'islamic', 'Islamic Golden Age', '980–1037 AD', 1008, 'high', 'The greatest philosopher-physician of the medieval world. His Canon of Medicine was the standard medical textbook in Europe for 600 years. His philosophical synthesis of Aristotelianism and Neoplatonism — including his "floating man" thought experiment anticipating Descartes'' cogito — profoundly influenced Aquinas and Latin Scholasticism.', true),
('philosopher_al_ghazali', 'Al-Ghazali', 'philosopher', 'islamic', 'Islamic Golden Age', '1058–1111 AD', 1084, 'high', 'The philosopher who attacked philosophy. His Incoherence of the Philosophers argued that Aristotelian philosophy — as developed by Al-Farabi and Avicenna — contradicted Islamic theology on three points: the eternity of the world, God''s knowledge of particulars, and bodily resurrection. His victory over rationalism in Islamic thought is one of history''s most consequential intellectual defeats.', true),
('philosopher_averroes', 'Averroes (Ibn Rushd)', 'philosopher', 'islamic', 'Islamic Golden Age', '1126–1198 AD', 1162, 'maximum', 'The Commentator — Dante''s name for him. His systematic commentaries on Aristotle were the vehicle through which Aristotle re-entered Western thought and made Aquinas possible. His defense of reason against Al-Ghazali''s attack (The Incoherence of the Incoherence) preserved the rationalist tradition in Islamic philosophy. He represents the road not taken — what Islamic philosophy might have become had reason prevailed over faith.', true),
('philosopher_ibn_khaldun', 'Ibn Khaldun', 'philosopher', 'islamic', 'Medieval', '1332–1406 AD', 1369, 'high', 'The founder of sociology and philosophy of history. His Muqaddimah — introduction to universal history — developed the first systematic theory of how civilizations rise and fall through asabiyyah (social cohesion). His cyclical theory of history anticipates Vico, Hegel, and Spengler. The most original thinker in the Islamic tradition after Averroes.', true),

-- WESTERN MEDIEVAL AND EARLY MODERN
('philosopher_augustine', 'Augustine of Hippo', 'philosopher', 'western', 'Roman Empire', '354–430 AD', 392, 'high', 'The philosopher who synthesized Neoplatonism with Christian theology. His Confessions established introspective autobiography as a philosophical genre. His City of God distinguished the earthly city (political power) from the heavenly city (spiritual community) — a distinction that would shape Western political thought for a millennium.', true),
('philosopher_aquinas', 'Thomas Aquinas', 'philosopher', 'western', 'Middle Ages', '1225–1274 AD', 1249, 'maximum', 'The greatest medieval philosopher. His life project: demonstrating that Aristotelian reason and Christian faith are compatible rather than contradictory. His Summa Theologica defined Catholic intellectual tradition. He received Aristotle through Averroes''s commentaries — making Islamic philosophy the bridge between ancient Greece and medieval Europe.', true),
('philosopher_ockham', 'William of Ockham', 'philosopher', 'western', 'Middle Ages', '1287–1347 AD', 1317, 'standard', 'The philosopher of Ockham''s Razor — "do not multiply entities beyond necessity." His nominalism — that universal concepts are merely names, not real things — attacked the Platonic-Aristotelian realism of Aquinas. His insistence on empirical particulars over abstract universals anticipated empiricism and the scientific method.', true),
('philosopher_machiavelli', 'Machiavelli', 'philosopher', 'western', 'Renaissance', '1469–1527', 1498, 'high', 'The first modern political philosopher. Separated political analysis from theology and morality, studying power as it actually functions. The Prince is the founding document of political realism — a tradition that runs through Hobbes, Clausewitz, and modern international relations theory.', true),
('philosopher_bacon', 'Francis Bacon', 'philosopher', 'western', 'Renaissance', '1561–1626', 1593, 'high', 'Father of the scientific method. Against Aristotelian deduction from first principles, Bacon insisted on inductive reasoning from systematic observation and experiment. His vision of organized empirical inquiry shaped the Royal Society and the institutional structure of modern science.', true),
('philosopher_hobbes', 'Thomas Hobbes', 'philosopher', 'western', 'Enlightenment', '1588–1679', 1633, 'high', 'The philosopher of the social contract as coercive necessity. Without sovereign authority, human life is "solitary, poor, nasty, brutish, and short." His Leviathan argued that individuals surrender their natural freedom to an absolute sovereign in exchange for security. The foundational text of modern political philosophy — and the argument Locke and Rousseau spent their careers answering.', true),
('philosopher_spinoza', 'Baruch Spinoza', 'philosopher', 'western', 'Enlightenment', '1632–1677', 1654, 'high', 'The philosopher of God-or-Nature. His pantheism — that God and Nature are one substance with infinite attributes — was the most radical philosophical system of the 17th century. Excommunicated from his Jewish community. His Ethics, written geometrically (definitions, axioms, propositions), attempted to derive all of philosophy from first principles by pure reason.', true),

-- ENLIGHTENMENT
('philosopher_descartes', 'René Descartes', 'philosopher', 'western', 'Enlightenment', '1596–1650', 1623, 'maximum', 'Father of modern philosophy. His method of radical doubt — stripping away everything uncertain until reaching bedrock certainty — produced "I think, therefore I am." Founded the mind-body problem. His mathematical rationalism shaped Spinoza, Leibniz, and the entire Continental tradition.', true),
('philosopher_leibniz', 'Gottfried Leibniz', 'philosopher', 'western', 'Enlightenment', '1646–1716', 1681, 'high', 'Co-inventor of calculus (with Newton) and philosopher of pre-established harmony. His monadology — reality consists of simple, non-extended substances (monads) whose apparent interaction is divinely coordinated — was the most elaborate rationalist metaphysics. His optimism ("this is the best of all possible worlds") was famously mocked by Voltaire after the Lisbon earthquake.', true),
('philosopher_locke', 'John Locke', 'philosopher', 'western', 'Enlightenment', '1632–1704', 1668, 'maximum', 'The philosopher of liberty. Grounded government in the consent of the governed and individual rights in natural law. His theory — life, liberty, property — became the intellectual foundation of liberal democracy and directly shaped the American Declaration of Independence. The most politically consequential philosopher in history after Aristotle.', true),
('philosopher_montesquieu', 'Montesquieu', 'philosopher', 'western', 'Enlightenment', '1689–1755', 1722, 'high', 'Philosopher of the separation of powers and the rule of law. His Spirit of the Laws analyzed how laws must fit the character of peoples and climates — pioneering comparative political science. His separation of legislative, executive, and judicial power became the structural foundation of constitutional democracy worldwide.', true),
('philosopher_voltaire', 'Voltaire', 'philosopher', 'western', 'Enlightenment', '1694–1778', 1736, 'high', 'The great destroyer of superstition. His satirical attacks on religious fanaticism, institutional corruption, and intellectual dogmatism made him the defining voice of the Enlightenment''s critical spirit. Famously read Confucius and praised Chinese governance as evidence that good society is possible without Christianity.', true),
('philosopher_hume', 'David Hume', 'philosopher', 'western', 'Enlightenment', '1711–1776', 1743, 'maximum', 'The most radical empiricist. Argued causation, personal identity, and moral facts cannot be derived from reason — only from habit and sentiment. His skepticism about induction remains unresolved. He awoke Kant from dogmatic slumber and shaped modern epistemology, philosophy of science, and metaethics.', true),
('philosopher_rousseau', 'Jean-Jacques Rousseau', 'philosopher', 'western', 'Enlightenment', '1712–1778', 1750, 'high', 'The philosopher of the general will and natural goodness corrupted by civilization. His Social Contract provided the ideological foundation for the French Revolution and the concept of popular sovereignty. The most dangerous Enlightenment thinker — his ideas in the wrong hands produced the Terror.', true),
('philosopher_kant', 'Immanuel Kant', 'philosopher', 'western', 'Enlightenment', '1724–1804', 1764, 'maximum', 'The philosopher''s philosopher. Attempted to reconcile empiricism and rationalism by showing that the mind actively structures experience. His categorical imperative grounded morality in reason and universalizability. His thing-in-itself — reality as it is beyond human cognition — simultaneously limited reason and rehabilitated faith, making him the most consequential and most contested philosopher of modernity.', true),
('philosopher_smith', 'Adam Smith', 'philosopher', 'western', 'Enlightenment', '1723–1790', 1756, 'maximum', 'Father of modern economics. The Wealth of Nations demonstrated that free markets, guided by the invisible hand of self-interest, produce social prosperity without central direction. His moral philosophy (Theory of Moral Sentiments) preceded and grounded his economics — he was a moral philosopher first.', true),
('philosopher_burke', 'Edmund Burke', 'philosopher', 'western', 'Enlightenment', '1729–1797', 1763, 'high', 'The father of modern conservatism. His Reflections on the Revolution in France — written before the Terror — predicted that abstract rationalist principles applied to politics produce destruction. Society is a partnership between the dead, the living, and the unborn — not a machine to be redesigned by ideology.', true),
('philosopher_wollstonecraft', 'Mary Wollstonecraft', 'philosopher', 'western', 'Enlightenment', '1759–1797', 1778, 'high', 'The first systematic feminist philosopher. Her Vindication of the Rights of Woman applied Enlightenment rationalism to women''s condition — if reason is the standard of human dignity, women possess it equally and must be treated equally. The founding document of liberal feminism.', true),

-- 19TH CENTURY
('philosopher_hegel', 'Georg Hegel', 'philosopher', 'western', '19th Century', '1770–1831', 1800, 'maximum', 'The philosopher of history and dialectic. Argued that reality is the self-development of Absolute Spirit through contradiction and synthesis. History is not contingent but necessary — the unfolding of reason in time. His influence on Marx (materialist inversion), existentialism (reaction against), and 20th century thought generally is immeasurable.', true),
('philosopher_schopenhauer', 'Arthur Schopenhauer', 'philosopher', 'western', '19th Century', '1788–1860', 1824, 'high', 'The philosopher of the will and pessimism. Argued that beneath Kant''s phenomena is blind, striving, purposeless Will — the source of all suffering. His encounter with Indian philosophy (the first major Western philosopher to engage Buddhism and Hinduism seriously) produced a synthesis that influenced Nietzsche, Freud, and Wagner.', true),
('philosopher_marx', 'Karl Marx', 'philosopher', 'western', '19th Century', '1818–1883', 1848, 'maximum', 'The most consequential political philosopher of modernity. His materialist analysis of capitalism — exploitation, alienation, class struggle — became the ideological foundation of communist movements that shaped the 20th century. Whether judged as prophet or destroyer, no thinker between Aristotle and the present has had greater political impact.', true),
('philosopher_mill', 'John Stuart Mill', 'philosopher', 'western', '19th Century', '1806–1873', 1848, 'high', 'The definitive liberal philosopher. His harm principle — liberty should only be restricted to prevent harm to others — remains the foundation of liberal political thought. United utilitarianism with liberalism and championed women''s equality when it was politically radioactive to do so.', true),
('philosopher_kierkegaard', 'Søren Kierkegaard', 'philosopher', 'western', '19th Century', '1813–1855', 1840, 'high', 'The first existentialist. Against Hegel''s impersonal dialectic, Kierkegaard insisted on the irreducible reality of the individual subject facing absolute choices without rational guidance. His "leap of faith" — choosing Christianity against rational evidence — made him the patron saint of irrationalist philosophy and the ancestor of 20th century existentialism.', true),
('philosopher_nietzsche', 'Friedrich Nietzsche', 'philosopher', 'western', '19th Century', '1844–1900', 1872, 'maximum', 'The philosopher of the will to power and the death of God. Declared that traditional morality is a slave revolt against excellence — the weak imposing their values on the strong through ressentiment. His Übermensch was a cultural ideal of self-overcoming through creative excellence, catastrophically distorted by Nazi ideology after his death. One of the most dangerous and most misread thinkers in history.', true),

-- 20TH CENTURY
('philosopher_russell', 'Bertrand Russell', 'philosopher', 'western', '20th Century', '1872–1970', 1921, 'high', 'The philosopher of logical atomism and mathematical logic. With Whitehead, wrote Principia Mathematica — the attempt to ground all mathematics in pure logic. His political activism (anti-war, nuclear disarmament) made him the model of the philosopher as public intellectual. His philosophical skepticism and defense of reason against all forms of mysticism defined Anglo-American philosophy.', true),
('philosopher_wittgenstein', 'Ludwig Wittgenstein', 'philosopher', 'western', '20th Century', '1889–1951', 1920, 'high', 'The philosopher who philosophized twice — with contradictory conclusions. The Tractatus: "Whereof one cannot speak, thereof one must be silent" — a logical positivist''s purge of metaphysics. The Investigations: language is a form of life, meaning is use — a demolition of the Tractatus. He transformed philosophy of language twice in one lifetime.', true),
('philosopher_heidegger', 'Martin Heidegger', 'philosopher', 'western', '20th Century', '1889–1976', 1927, 'high', 'The most controversial philosopher of the 20th century. His Being and Time — the question of what it means to be — transformed existentialism and phenomenology. His Nazi membership remains a permanent stain that philosophers cannot resolve: can the thought be separated from the thinker? His influence on continental philosophy, theology, and postmodernism is immense.', true),
('philosopher_popper', 'Karl Popper', 'philosopher', 'western', '20th Century', '1902–1994', 1934, 'high', 'Philosopher of science and open society. His falsifiability criterion distinguished science from pseudoscience. The Open Society and Its Enemies — written while fleeing Nazi Europe — remains the definitive philosophical critique of totalitarianism and Platonic utopianism. One of the most important defenders of reason and liberal democracy in the 20th century.', true),
('philosopher_hayek', 'Friedrich Hayek', 'philosopher', 'western', '20th Century', '1899–1992', 1944, 'high', 'The defender of spontaneous order. The Road to Serfdom argued central planning inevitably leads to tyranny — not from the malice of planners but from the epistemological impossibility of centralized knowledge. His work on markets, knowledge, and freedom defined modern classical liberalism and libertarian thought.', true),
('philosopher_arendt', 'Hannah Arendt', 'philosopher', 'western', '20th Century', '1906–1975', 1951, 'high', 'The philosopher of totalitarianism and the human condition. Her Origins of Totalitarianism identified Nazism and Stalinism as qualitatively new forms of evil — grounded in ideology rather than mere self-interest. Her report on the Eichmann trial produced the phrase "the banality of evil" — bureaucratic thoughtlessness as the vehicle for genocide.', true),
('philosopher_sartre', 'Jean-Paul Sartre', 'philosopher', 'western', '20th Century', '1905–1980', 1943, 'standard', 'The philosopher of radical freedom and bad faith. Existence precedes essence — humans have no fixed nature, only choices. His existentialism shaped the European left and the 1968 generation. His tortured relationship with Soviet communism — defending atrocities he privately condemned — exemplifies the moral failures of 20th century intellectual life.', true),
('philosopher_rawls', 'John Rawls', 'philosopher', 'western', '20th Century', '1921–2002', 1971, 'high', 'The most influential political philosopher of the 20th century in Anglo-American academia. His veil of ignorance — design society without knowing your position — produces principles protecting the worst-off. A Theory of Justice revived normative political philosophy and defined liberal egalitarianism for a generation.', true),
('philosopher_foucault', 'Michel Foucault', 'philosopher', 'western', '20th Century', '1926–1984', 1961, 'high', 'The philosopher of power and knowledge. Analyzed how institutions — prisons, hospitals, asylums, schools — shape human subjects through normalization and surveillance. His genealogical method traced how power produces truth. His influence on postmodern thought, gender studies, and critical theory is vast and contested.', true),
('philosopher_rand', 'Ayn Rand', 'philosopher', 'western', '20th Century', '1905–1982', 1943, 'standard', 'Russian-born American philosopher and novelist who developed Objectivism — a comprehensive philosophical system. Its four branches: Metaphysics (reality exists independent of consciousness), Epistemology (reason is the only valid means of knowledge), Ethics (rational self-interest is the proper standard of value), Politics (individual rights and laissez-faire capitalism are the only moral social system). The Fountainhead (1943) and Atlas Shrugged (1957) dramatized these ideas. She identified Aristotle as the greatest philosopher in history and her primary ancestor, and Kant as the most destructive force in modern philosophy.', true)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- SEED DATA: HISTORICAL EVENTS
-- ============================================================

INSERT INTO graph_nodes (id, label, type, tradition, era, years, year_numeric, weight, description, is_seed) VALUES
('event_trial_socrates', 'Trial of Socrates', 'event', 'western', 'Ancient Greece', '399 BC', -399, 'high', 'Athens tried and executed Socrates for impiety and corrupting youth. The first philosopher martyred for ideas — and the defining moment of the tension between free inquiry and democratic conformism. Plato''s response was to distrust democracy forever.', true),
('event_alexander_conquests', 'Conquests of Alexander', 'event', 'western', 'Ancient Greece', '334–323 BC', -334, 'high', 'Alexander spread Greek culture across Persia, Egypt, and into India, creating the Hellenistic world and the first great East-West intellectual exchange. Philosophy became cosmopolitan for the first time.', true),
('event_destruction_nalanda', 'Destruction of Nalanda', 'event', 'indian', 'Islamic Golden Age', '1193 AD', 1193, 'high', 'The destruction of Nalanda University — the greatest center of Buddhist learning in the world — by Turkic invaders. Its library burned for months. The catastrophic end of classical Indian Buddhist philosophy as a living tradition on the subcontinent.', true),
('event_fall_rome', 'Fall of Rome', 'event', 'western', 'Roman Empire', '476 AD', 476, 'high', 'The collapse of the Western Roman Empire ended Mediterranean unity and plunged Western Europe into fragmented kingdoms. Classical learning survived only in monasteries and — crucially — in the Islamic world, which preserved what Europe forgot.', true),
('event_translation_movement', 'Islamic Translation Movement', 'event', 'islamic', 'Islamic Golden Age', '830–1000 AD', 900, 'maximum', 'The systematic translation of Greek philosophical and scientific texts into Arabic under the Abbasid Caliphate — the most consequential act of intellectual preservation in history. Without it, Aristotle, Plato, Euclid, and Galen would have been lost to Western civilization. The House of Wisdom in Baghdad was the knowledge center of the medieval world.', true),
('event_magna_carta', 'Magna Carta', 'event', 'western', 'Middle Ages', '1215 AD', 1215, 'high', 'The first formal limitation of royal power — establishing that the king is subject to law. The foundation from which constitutional government, parliamentary sovereignty, and eventually liberal democracy developed over subsequent centuries.', true),
('event_black_death', 'Black Death', 'event', 'western', 'Middle Ages', '1347–1351 AD', 1349, 'high', 'The bubonic plague killed one-third of Europe''s population. Its philosophical consequence: unprecedented questioning of providential order. If God is good and omnipotent, why this? The Black Death accelerated the crisis of medieval theology and the turn toward Renaissance humanism.', true),
('event_printing_press', 'Gutenberg Printing Press', 'event', 'western', 'Renaissance', '1440', 1440, 'maximum', 'The most transformative technology before the internet. Mass reproduction of text broke the Church''s monopoly on literacy and knowledge, enabling the Reformation, the Scientific Revolution, and the Enlightenment. Ideas could now spread faster than institutions could suppress them.', true),
('event_protestant_reformation', 'Protestant Reformation', 'event', 'western', 'Renaissance', '1517', 1517, 'high', 'Luther''s challenge to papal authority fractured Western Christianity and unleashed a century of religious warfare. Its philosophical consequence: individual conscience against institutional authority — the principle that every person can read and interpret scripture for themselves. A precursor of Enlightenment individualism.', true),
('event_scientific_revolution', 'Scientific Revolution', 'event', 'western', 'Renaissance', '1543–1687', 1615, 'maximum', 'Copernicus, Galileo, Kepler, and Newton overturned the Aristotelian-Christian cosmology that had governed educated thought for 1,500 years. Established empirical observation and mathematics as the standard of truth. The single most consequential intellectual event in human history.', true),
('event_american_revolution', 'American Revolution', 'event', 'western', 'Enlightenment', '1775–1783', 1776, 'high', 'The first successful colonial revolution, grounded explicitly in Lockean natural rights. The Declaration of Independence operationalized Enlightenment philosophy into a founding political document — the most successful application of philosophical principles to political construction in history.', true),
('event_french_revolution', 'French Revolution', 'event', 'western', 'Enlightenment', '1789–1799', 1789, 'maximum', 'The most consequential political event of the modern era. Destroyed the ancien régime, established popular sovereignty, and introduced the ideological spectrum of left and right. Its Terror revealed the catastrophic potential of abstract philosophical principles applied to politics without institutional constraint.', true),
('event_industrial_revolution_event', 'Industrial Revolution', 'event', 'western', '19th Century', '1760–1840', 1800, 'maximum', 'The transformation of production through machinery and capital. Created the modern working class, mass urbanization, and the material conditions for both liberal capitalism and socialist revolution. Every major 19th century philosophy is a response to industrialization.', true),
('event_publication_communist_manifesto', 'Communist Manifesto Published', 'event', 'western', '19th Century', '1848', 1848, 'high', 'Marx and Engels published the most politically consequential pamphlet in history. Its analysis of class struggle and call for proletarian revolution became the ideological blueprint for movements that governed half the world by the mid-20th century.', true),
('event_darwins_origin', 'Darwin''s Origin of Species', 'event', 'western', '19th Century', '1859', 1859, 'maximum', 'Darwin''s theory of evolution by natural selection was the most philosophically disruptive scientific discovery since Copernicus. It removed purpose and design from biology, challenged the theological foundations of morality, and forced every philosopher to reckon with humanity''s animal nature.', true),
('event_ww1', 'World War I', 'event', 'western', '20th Century', '1914–1918', 1914, 'maximum', 'The catastrophic collapse of the liberal European order. Killed 20 million people, destroyed four empires, and shattered the Enlightenment faith in inevitable progress. Produced the psychological and political conditions for fascism, communism, and World War II.', true),
('event_russian_revolution', 'Russian Revolution', 'event', 'western', '20th Century', '1917', 1917, 'maximum', 'The first successful Marxist revolution. Established the Soviet Union and launched the 70-year experiment in central planning and one-party rule. The most consequential political event of the 20th century — and the greatest disproof of utopian rationalism in history.', true),
('event_rise_nazism', 'Rise of Nazism', 'event', 'western', '20th Century', '1933', 1933, 'maximum', 'Hitler''s appointment as German Chancellor. The democratic Weimar Republic peacefully transferred power to a movement built on racial ideology, nationalist resentment, and the systematic destruction of reason in political life. The most catastrophic failure of a civilization to protect itself from ideas.', true),
('event_ww2', 'World War II', 'event', 'western', '20th Century', '1939–1945', 1939, 'maximum', 'The deadliest conflict in human history — 70-85 million dead. Produced the Holocaust, atomic weapons, the United Nations, and the postwar liberal international order. Permanently redefined the meaning of evil and the obligations of civilization.', true),
('event_holocaust', 'The Holocaust', 'event', 'western', '20th Century', '1941–1945', 1941, 'maximum', 'The systematic murder of six million Jews and millions of others. Forced philosophy to confront how rational bureaucracies produce industrialized mass murder — and whether the Western philosophical tradition bears partial responsibility for its own worst historical outcome.', true),
('event_india_independence', 'Indian Independence', 'event', 'indian', '20th Century', '1947', 1947, 'high', 'The end of British colonial rule — achieved largely through Gandhi''s non-violent resistance. The most successful application of philosophical principles to anti-colonial struggle. Demonstrated that satyagraha could defeat a global empire without conventional military force.', true),
('event_cold_war', 'Cold War', 'event', 'universal', '20th Century', '1947–1991', 1969, 'maximum', 'The ideological confrontation between American capitalism and Soviet communism. Defined global politics for four decades. The greatest real-world experiment in the battle between free markets and central planning — and between individual rights and collective sovereignty.', true),
('event_cultural_revolution', 'Chinese Cultural Revolution', 'event', 'chinese', '20th Century', '1966–1976', 1971, 'high', 'Mao''s attempt to purge China of traditional culture, Confucian values, and intellectual life. Destroyed an estimated 1.6 million lives and persecuted millions more. The most systematic philosophical act of self-destruction in history — a civilization attempting to erase its own intellectual foundations.', true),
('event_fall_berlin_wall', 'Fall of the Berlin Wall', 'event', 'western', '20th Century', '1989', 1989, 'high', 'The symbolic end of the Cold War and collapse of Soviet communism in Eastern Europe. Appeared to confirm Hayek and Popper''s arguments against central planning and totalitarianism. Fukuyama declared the "end of history" — liberal democracy as the final form of human organization. History disagreed.', true),
('event_september_11', 'September 11 Attacks', 'event', 'universal', 'Contemporary', '2001', 2001, 'high', 'The deadliest terrorist attack in history. Raised the question of whether liberal societies can defend themselves without betraying their values — and began a global reckoning with the relationship between religion, violence, and political philosophy.', true),
('event_2008_financial_crisis', '2008 Financial Crisis', 'event', 'western', 'Contemporary', '2008', 2008, 'high', 'The collapse of global financial markets. The largest economic shock since the Great Depression. Revived debates about capitalism''s stability, market regulation, and the relationship between financial power and democratic governance.', true),
('event_ai_revolution', 'AI Revolution', 'event', 'universal', 'Contemporary', '2020–present', 2022, 'high', 'The deployment of large language models into every domain of human activity. Forces philosophy to revisit fundamental questions about consciousness, creativity, labor, and the nature of intelligence — the Axial Age questions returning in technological form.', true)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- SEED DATA: CONCEPTS
-- ============================================================

INSERT INTO graph_nodes (id, label, type, tradition, era, years, year_numeric, weight, description, is_seed) VALUES
('concept_reason', 'Reason', 'concept', 'universal', 'All Eras', 'Ancient–Present', -500, 'maximum', 'The faculty of logical inference from evidence and principles. The central concept of the Western philosophical tradition and the standard Objectivism holds as the only valid means of knowledge. In tension with faith, tradition, sentiment, and will across every philosophical era.', true),
('concept_tao', 'The Tao', 'concept', 'chinese', 'Classical China', '6th century BC', -550, 'high', 'The Way — the underlying principle of reality in Taoist philosophy. Cannot be named, defined, or grasped conceptually — only lived in harmony with. Stands in fundamental opposition to Western rationalism: the highest wisdom is not systematic reason but effortless attunement to natural order (wu wei).', true),
('concept_dharma', 'Dharma', 'concept', 'indian', 'Classical India', '800 BC–Present', -500, 'high', 'One of the most complex concepts in Indian philosophy — simultaneously cosmic order, ethical duty, right conduct, and the teachings of the Buddha. Its multiple meanings across Hinduism, Buddhism, and Jainism reflect the Indian philosophical tradition''s resistance to univocal definitions.', true),
('concept_sunyata', 'Sunyata (Emptiness)', 'concept', 'indian', 'Classical India', '150 AD', 200, 'high', 'Nagarjuna''s concept that all phenomena lack inherent, independent existence — they arise only in dependence on conditions. Not nihilism (things don''t exist) but the denial of intrinsic essence. The most rigorous philosophical challenge to both Western realism and Indian idealism.', true),
('concept_logos', 'Logos', 'concept', 'western', 'Ancient Greece', '500 BC', -500, 'high', 'Reason, word, principle — the rational order underlying reality in Greek philosophy. Heraclitus''s cosmic fire. Stoic divine reason. In John''s Gospel, the divine Word. The concept that reason is not merely human but cosmic — built into the structure of reality.', true),
('concept_natural_rights', 'Natural Rights', 'concept', 'western', 'Enlightenment', '17th Century', 1650, 'maximum', 'The doctrine that individuals possess rights — life, liberty, property — independent of government, derived from reason and human nature. The foundation of classical liberalism and the intellectual basis of both the American and French Revolutions — with radically different outcomes.', true),
('concept_social_contract', 'Social Contract', 'concept', 'western', 'Enlightenment', '17th–18th Century', 1680, 'high', 'The theory that legitimate political authority derives from the consent of the governed. Hobbes, Locke, and Rousseau each developed incompatible versions with incompatible political implications — from absolute sovereignty to liberal rights to totalitarian democracy.', true),
('concept_categorical_imperative', 'Categorical Imperative', 'concept', 'western', 'Enlightenment', '18th Century', 1785, 'high', 'Kant''s supreme principle of morality: act only according to principles you could will to be universal laws. Grounds ethics in reason and universalizability rather than consequences or divine command. The foundation of deontological ethics — and the ethics Rand most directly opposed.', true),
('concept_dialectic', 'Dialectic', 'concept', 'western', '19th Century', '1807', 1807, 'high', 'Hegel''s method of historical development through contradiction: thesis generates antithesis, which resolves into synthesis. Marx inverted it materially. The concept underlies all theories of historical progress through conflict — and is the philosophical foundation of both Marxism and fascism.', true),
('concept_class_struggle', 'Class Struggle', 'concept', 'western', '19th Century', '1848', 1848, 'high', 'Marx''s thesis that history is driven by conflict between economic classes. All political, legal, religious, and philosophical forms are superstructure built on the economic base of production relations. The foundation of all socialist and communist political programs.', true),
('concept_will_to_power', 'Will to Power', 'concept', 'western', '19th Century', '1883', 1883, 'high', 'Nietzsche''s fundamental drive of all living things — not mere survival but the drive to overcome, create, and expand one''s power. Catastrophically misread by Nazi ideologues as racial domination. Nietzsche himself despised German nationalism and antisemitism as symptoms of the slave morality he opposed.', true),
('concept_free_market', 'Free Market', 'concept', 'western', 'Enlightenment', '18th Century', 1776, 'high', 'The economic system in which prices and production are determined by voluntary exchange rather than central authority. Defended by Smith on efficiency grounds, by Hayek on epistemological grounds, and by Rand on moral grounds — as the only system consistent with individual rights.', true),
('concept_invisible_hand', 'Invisible Hand', 'concept', 'western', 'Enlightenment', '18th Century', 1776, 'standard', 'Adam Smith''s metaphor: individual self-interest, operating through voluntary exchange, produces social coordination without deliberate design. The philosophical foundation of market economics — and the concept Hayek deepened into spontaneous order theory.', true),
('concept_spontaneous_order', 'Spontaneous Order', 'concept', 'western', '20th Century', '1944', 1944, 'high', 'Hayek''s insight that complex institutions — markets, languages, laws, moral codes — emerge from individual actions without central design. The epistemological impossibility of central planning follows directly: no authority can possess the distributed knowledge that price systems process automatically.', true),
('concept_falsifiability', 'Falsifiability', 'concept', 'western', '20th Century', '1934', 1934, 'high', 'Popper''s criterion demarcating science from pseudoscience: a theory is scientific only if it makes predictions that could be proven wrong. Transformed the philosophy of science and established the standard of rational inquiry that distinguishes knowledge from ideology.', true),
('concept_totalitarianism', 'Totalitarianism', 'concept', 'western', '20th Century', '20th Century', 1951, 'high', 'Political systems that seek total control over all aspects of public and private life — distinguished from traditional tyranny by ideological grounding. Identified by Arendt and Popper as the uniquely modern form of political evil produced by secular utopianism replacing religious providence.', true),
('concept_open_society', 'Open Society', 'concept', 'western', '20th Century', '1945', 1945, 'high', 'Popper''s concept: societies organized around critical rationalism, tolerance, and the ability to change institutions without violence. Opposed to closed societies governed by tribal, religious, or ideological certainty. The philosophical foundation of liberal democratic order.', true),
('concept_separation_powers', 'Separation of Powers', 'concept', 'western', 'Enlightenment', '18th Century', 1748, 'high', 'Montesquieu''s doctrine that legislative, executive, and judicial functions must be held by separate institutions to prevent tyranny. The structural foundation of constitutional democracy worldwide.', true),
('concept_objectivism', 'Objectivism', 'concept', 'western', '20th Century', '1943–1979', 1957, 'standard', 'Ayn Rand''s philosophical system. Metaphysics: reality exists independent of consciousness. Epistemology: reason is the only valid means of knowledge. Ethics: rational self-interest is the proper standard of value. Politics: individual rights and laissez-faire capitalism are the only moral social system. Aesthetics: art must present a moral ideal through concrete sensory form. An integrated system grounded in the primacy of existence over consciousness.', true),
('concept_rational_self_interest', 'Rational Self-Interest', 'concept', 'western', '20th Century', '1964', 1964, 'standard', 'Ayn Rand''s ethical standard. Each individual''s own life and happiness are the highest moral purpose, pursued through reason rather than whim or instinct. Distinguished from hedonism (pursuit of pleasure) and exploitation (harming others) by its grounding in long-term rational values. Directly opposed to altruism — the moral code demanding self-sacrifice — which Rand identified as the philosophical foundation of collectivism.', true),
('concept_veil_of_ignorance', 'Veil of Ignorance', 'concept', 'western', '20th Century', '1971', 1971, 'standard', 'Rawls''s thought experiment: design a just society without knowing what position you will occupy in it. Rational agents behind this veil would choose principles protecting the worst-off. The most influential argument for redistributive justice in 20th century political philosophy — and Rand''s direct philosophical opposite.', true),
('concept_wu_wei', 'Wu Wei', 'concept', 'chinese', 'Classical China', '6th century BC', -550, 'high', 'Effortless action — action in harmony with the natural flow of things rather than against it. The Taoist alternative to both Confucian social engineering and Western rational planning. Not passivity but the highest form of activity: action without forcing, governing without dominating, achieving without striving.', true),
('concept_ren', 'Ren (Benevolence)', 'concept', 'chinese', 'Classical China', '500 BC', -500, 'high', 'The central virtue of Confucian ethics — humaneness, benevolence, love of humanity. The disposition to treat others with care, respect, and proper regard for their dignity within appropriate social relationships. Not universal love (which Confucius distinguished from ren) but graded love expressed through proper social roles.', true),
('concept_ahimsa', 'Ahimsa (Non-Violence)', 'concept', 'indian', 'Classical India', '6th century BC', -550, 'high', 'The principle of non-violence toward all living beings — the ethical foundation shared by Jainism, Buddhism, and certain schools of Hinduism. Gandhi transformed it from a personal ethical principle into a political strategy, demonstrating that non-violence could be a more powerful political force than military power.', true)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- SEED DATA: BATTLE DIMENSION NODES
-- ============================================================

INSERT INTO graph_nodes (id, label, type, tradition, era, years, year_numeric, weight, description, is_seed) VALUES
('battle_reality_mysticism', 'Reality vs Mysticism', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'maximum', 'The oldest and most fundamental battle in philosophy. Is reality objective — existing independent of consciousness, accessible through reason and observation? Or is ultimate reality accessible only through revelation, mystical experience, or faith? Every philosophical system takes a position on this axis.', true),
('battle_reason_faith', 'Reason vs Faith', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'maximum', 'Can reason alone reach truth, or does faith provide access to a higher truth beyond reason''s reach? The central tension of medieval philosophy in all traditions — Greek rationalism vs Christian theology, Islamic falsafa vs kalam, Buddhist logic vs Vedic revelation. The battle that never ends.', true),
('battle_individual_collective', 'Individual vs Collective', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'maximum', 'Is the individual or the group the fundamental unit of moral and political reality? The deepest political fault line in history — expressed as rights vs duty, liberty vs equality, capitalism vs socialism, liberal democracy vs authoritarianism. Every political philosophy takes sides.', true),
('battle_freedom_coercion', 'Freedom vs Coercion', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'maximum', 'The battle over the legitimate scope of political authority. When may the state compel individuals against their will? Libertarians and classical liberals draw the line at harm to others. Collectivists draw it at the general will. Totalitarians erase it entirely. Every political system is an answer to this question.', true),
('battle_creation_nihilism', 'Value Creation vs Nihilism', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'high', 'Are values real and achievable — is human life worth living on its own terms? Or are all values illusory, all striving futile, all meaning constructed? The battle between life-affirmation and life-negation runs from Epicurus vs Pyrrho through Nietzsche vs Schopenhauer to Rand vs postmodern nihilism.', true),
('battle_market_planning', 'Free Market vs Central Planning', 'battle', 'universal', '18th Century–Present', 1776, 'high', 'The battle over economic organization. Can decentralized voluntary exchange produce social order and prosperity? Or must rational authority coordinate production to serve the common good? The defining economic battle of modernity — resolved empirically in 1989 but ideologically unresolved.', true),
('battle_beauty_chaos', 'Harmonic Beauty vs Chaotic Ugliness', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'standard', 'The aesthetic dimension of the battle between order and chaos. Does art serve to elevate the human spirit by presenting reality and human potential in idealized, beautiful form? Or does it serve truth by presenting raw, chaotic, ugly reality without redemption? The battle between Romanticism and Naturalism, between Rand''s aesthetic idealism and postmodern anti-aesthetics.', true),
('battle_good_evil', 'Good vs Evil', 'battle', 'universal', 'All Eras', '600 BC–Present', -500, 'maximum', 'The oldest moral question: are good and evil real and distinguishable? Or are they cultural constructs, relative to perspective, or illusory from a cosmic standpoint? The battle between moral realism and moral relativism, between principled ethics and nihilism, between courage to judge and paralysis of cultural relativism.', true)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- SEED DATA: EDGES (RELATIONSHIPS)
-- ============================================================

INSERT INTO graph_edges (source_id, target_id, relation, battle_dimension, label, weight, is_seed) VALUES
-- PRE-SOCRATIC FOUNDATIONS
('philosopher_thales', 'philosopher_heraclitus', 'influenced', 'reality_vs_mysticism', 'Thales initiated the project of explaining reality through natural principles rather than myth. Heraclitus carried this further — but where Thales sought a single material principle (water), Heraclitus found a dynamic rational principle (Logos) governing perpetual flux. The move from matter to rational order.', 0.7, true),
('philosopher_heraclitus', 'philosopher_parmenides', 'responded_to', 'reality_vs_mysticism', 'Parmenides was the direct philosophical answer to Heraclitean flux. If everything changes, nothing can be known — knowledge requires stable objects. Parmenides concluded that change is illusion and only unchanging Being is real. The first great philosophical battle: flux vs permanence, appearance vs reality.', 0.9, true),
('philosopher_parmenides', 'philosopher_plato', 'influenced', 'reality_vs_mysticism', 'Plato''s theory of Forms is a resolution of the Parmenidean problem: the Forms are the unchanging, eternal realities that Parmenides required for knowledge, while the physical world of flux is demoted to mere appearance. Parmenides made Plato''s metaphysics necessary.', 0.85, true),
('philosopher_pythagoras', 'philosopher_plato', 'influenced', 'reality_vs_mysticism', 'Plato inherited from Pythagoras the idea that mathematical structures are more real than physical things, and that the soul is imprisoned in matter and seeks liberation. The Pythagorean mysticism of number and soul runs through the entire Platonic tradition.', 0.8, true),
('philosopher_democritus', 'philosopher_epicurus', 'influenced', 'reality_vs_mysticism', 'Epicurus adopted Democritus''s atomism wholesale — reality consists of atoms and void, nothing else. But where Democritus was a pure physicist, Epicurus made atomism the foundation of a practical ethics: if the world is atoms and void, there are no divine interventions to fear, and the good life consists of tranquil pleasure.', 0.85, true),
('philosopher_democritus', 'battle_reality_mysticism', 'derived_from', 'reality_vs_mysticism', 'Democritus represents the most uncompromising ancient assertion of objective material reality. Atoms and void — no gods, no souls, no purpose. His materialism is the ancient precursor of scientific naturalism and stands at the origin of the reason-vs-mysticism battle.', 0.9, true),

-- CLASSICAL GREEK CHAIN
('philosopher_socrates', 'philosopher_plato', 'influenced', null, 'Plato was Socrates'' most devoted student and our primary source for Socratic thought. He preserved Socratic dialogue in written form while transforming it into a comprehensive philosophical system. The question of where Socrates ends and Plato begins is permanently unresolved.', 1.0, true),
('philosopher_plato', 'philosopher_aristotle', 'responded_to', 'reality_vs_mysticism', 'Aristotle studied at Plato''s Academy for 20 years and rejected the theory of Forms root and branch. Forms don''t exist separately from things — they are immanent in things. This is the deepest fault line in Western philosophy: does reality reside in abstract ideals (Plato) or in concrete particulars (Aristotle)?', 0.95, true),
('philosopher_socrates', 'event_trial_socrates', 'caused', 'freedom_vs_coercion', 'Socrates'' relentless questioning of Athenian assumptions made him politically dangerous. The trial was democracy''s first act of philosophical censorship — a majority vote eliminating a critic it could not refute by argument. Plato''s distrust of democracy begins here.', 0.9, true),
('philosopher_aristotle', 'event_alexander_conquests', 'influenced', null, 'Aristotle tutored Alexander from age 13, instilling Greek philosophical values and the concept of a civilizing mission. Alexander carried Greek culture across three continents — the most consequential outcome of a philosophical education in history, and the first great East-West intellectual contact.', 0.7, true),

-- HELLENISTIC AND ROMAN
('philosopher_aristotle', 'philosopher_zeno_stoic', 'influenced', null, 'Stoicism built on Aristotelian virtue ethics — the idea that virtue is the highest good and consists in the exercise of rational faculties. But Stoics radicalized it: virtue is the only good, and external circumstances (wealth, health, reputation) are entirely indifferent to happiness.', 0.7, true),
('philosopher_zeno_stoic', 'philosopher_marcus_aurelius', 'influenced', 'reason_vs_faith', 'Marcus Aurelius represents Stoicism applied under conditions of absolute power. His Meditations demonstrate that rational self-governance is not merely theoretical — it is a daily practice of aligning one''s judgments with reason regardless of external circumstances, including governing an empire.', 0.85, true),
('philosopher_plato', 'philosopher_plotinus', 'influenced', 'reality_vs_mysticism', 'Plotinus carried Platonic idealism to its mystical conclusion: the One — beyond being and thought — is the source from which all reality emanates. His Neoplatonism transformed Plato''s philosophical idealism into a mystical system that profoundly shaped both Christian theology and Islamic philosophy.', 0.85, true),
('philosopher_plotinus', 'philosopher_augustine', 'influenced', 'reason_vs_faith', 'Augustine was a Neoplatonist before he was a Christian, and he never ceased being one. He read Plato through Plotinus and found Christianity''s God in the Plotinian One. His synthesis of Neoplatonism and Christian theology defined Western Christian thought for a millennium.', 0.9, true),

-- CHINESE TRUNK
('philosopher_laozi', 'philosopher_zhuangzi', 'influenced', 'individualism_vs_collectivism', 'Zhuangzi radicalized Laozi''s Taoism — where Laozi offered aphoristic wisdom about governing, Zhuangzi developed a philosophy of radical individual freedom and perspectivism. No fixed social role (Confucian) or natural order (Laozi) can fully contain the free individual who recognizes the relativity of all standpoints.', 0.9, true),
('philosopher_confucius', 'philosopher_mencius', 'influenced', 'good_vs_evil', 'Mencius developed Confucius''s ethics in a crucial direction: human nature is fundamentally good, not neutral or corrupt. Moral cultivation is recovery of innate goodness, not imposition of external norms. This optimistic anthropology distinguishes Confucianism from Legalism and from Christian original sin.', 0.9, true),
('philosopher_confucius', 'philosopher_han_fei', 'responded_to', 'individualism_vs_collectivism', 'Han Fei systematically rejected every premise of Confucianism. Human nature is selfish, not good. Virtue ethics is naive — only law, punishment, and calculated incentives produce social order. The ruler who trusts virtue will be overthrown; the ruler who controls incentives will prevail. Political realism vs moral idealism.', 0.85, true),
('philosopher_laozi', 'philosopher_confucius', 'responded_to', 'freedom_vs_coercion', 'The Confucius-Laozi relationship is the central tension of classical Chinese philosophy. Confucius sought to restore social harmony through proper relationships, ritual, and moral cultivation — active social engineering. Laozi argued that all social engineering disturbs the natural Tao — the best governance governs least.', 0.85, true),
('philosopher_confucius', 'era_classical_china', 'derived_from', null, 'Confucianism became the intellectual framework of Chinese civilization for 2,500 years — shaping governance, family structure, education, and ethics across dynastic changes, invasions, and revolutions. No other philosophical tradition has governed so large a population for so long.', 0.9, true),
('philosopher_han_fei', 'event_cultural_revolution', 'fulfills_legacy_of', 'freedom_vs_coercion', 'Mao''s Cultural Revolution paradoxically combined Marxist collectivism with Legalist methods of social control — mass campaigns, terror, and the systematic destruction of traditional culture. The Legalist contempt for tradition and reliance on raw power found its most destructive modern expression in Maoism.', 0.6, true),

-- INDIAN TRUNK
('philosopher_upanishads', 'philosopher_buddha', 'responded_to', 'reality_vs_mysticism', 'The Buddha arose within the Upanishadic tradition and fundamentally challenged it. He accepted the Upanishadic diagnosis (life is suffering, driven by attachment and illusion) but rejected the prescribed cure (union with Atman/Brahman). There is no permanent self — neither individual (Atman) nor universal (Brahman). This is the deepest internal rupture in Indian philosophy.', 0.95, true),
('philosopher_upanishads', 'philosopher_shankara', 'influenced', 'reality_vs_mysticism', 'Shankara''s Advaita Vedanta was the most rigorous philosophical defense of Upanishadic non-dualism against Buddhist no-self philosophy. Brahman alone is real; the multiplicity of selves and world is maya (illusion). His synthesis responded to Buddhist philosophy using Buddhist logical tools against Buddhist conclusions.', 0.9, true),
('philosopher_buddha', 'philosopher_nagarjuna', 'influenced', 'reality_vs_mysticism', 'Nagarjuna developed the philosophical implications of the Buddha''s anatta doctrine to their logical conclusion. If all phenomena lack inherent existence, then even the Buddha''s own doctrines lack inherent existence — sunyata applies to itself. This dialectical move transforms Buddhism from a doctrine into a philosophical method.', 0.95, true),
('philosopher_buddha', 'philosopher_shankara', 'responded_to', 'reality_vs_mysticism', 'Shankara''s entire philosophical project was a systematic refutation of Buddhist philosophy, particularly Nagarjuna''s Madhyamaka. He argued that sunyata (emptiness) collapses into nihilism without a positive metaphysical foundation — which only Brahman can provide. The great debate between Buddhism and Advaita Vedanta shaped Indian philosophy for centuries.', 0.85, true),
('philosopher_mahavira', 'philosopher_buddha', 'responded_to', 'individualism_vs_collectivism', 'Mahavira and the Buddha were near-contemporaries who developed distinct responses to Upanishadic religion. Both rejected caste hierarchy and Vedic ritual authority. But where Buddha taught a middle way between extreme asceticism and indulgence, Mahavira advocated the most rigorous asceticism in history as the path to liberation.', 0.7, true),
('philosopher_schopenhauer', 'philosopher_upanishads', 'derived_from', 'reality_vs_mysticism', 'Schopenhauer was the first major Western philosopher to engage Indian philosophy seriously. His discovery of the Upanishads confirmed what he had independently concluded: the phenomenal world is appearance (maya), and the will is the blind, purposeless reality beneath. He called this the greatest consolation he had ever received.', 0.8, true),
('philosopher_gandhi', 'concept_ahimsa', 'applied_in', 'freedom_vs_coercion', 'Gandhi transformed ahimsa from a personal ethical principle — don''t harm living beings — into a political strategy for resisting coercive authority. Satyagraha (truth-force) uses non-violent resistance to make coercion visible and morally intolerable. His political application of Indian philosophical ethics was a genuine philosophical innovation.', 0.95, true),
('philosopher_gandhi', 'event_india_independence', 'caused', 'freedom_vs_coercion', 'Gandhi''s satyagraha campaigns made British colonial rule politically untenable without military force the British were unwilling to use. The philosophical method produced the political result — the most successful application of non-violent philosophical principles to anti-colonial struggle in history.', 0.9, true),

-- ISLAMIC TRUNK
('event_translation_movement', 'philosopher_al_kindi', 'caused', null, 'The Islamic Translation Movement created the intellectual context in which Al-Kindi could work. Without Arabic translations of Aristotle, Plato, and the Neoplatonists, there is no Islamic philosophy. Al-Kindi was the first thinker to work directly within the tradition the Translation Movement created.', 0.9, true),
('philosopher_al_kindi', 'philosopher_al_farabi', 'influenced', 'reason_vs_faith', 'Al-Farabi built directly on Al-Kindi''s project of reconciling Greek philosophy with Islamic theology — but went further, developing a comprehensive Aristotelian-Platonic synthesis and a political philosophy derived from it. Al-Kindi opened the door; Al-Farabi walked through it.', 0.85, true),
('philosopher_al_farabi', 'philosopher_avicenna', 'influenced', 'reason_vs_faith', 'Avicenna described reading Al-Farabi''s commentary on Aristotle''s Metaphysics 40 times without understanding it — then reading Al-Farabi''s own work and immediately understanding it. Al-Farabi was the indispensable guide to Aristotle for the Islamic world, and thus for Avicenna''s entire philosophical project.', 0.9, true),
('philosopher_avicenna', 'philosopher_aquinas', 'influenced', 'reason_vs_faith', 'Aquinas received Aristotle partly through Avicenna''s commentaries and syntheses. Avicenna''s proof for the existence of a Necessary Being (the Floating Man argument), his distinction between essence and existence, and his psychology all appear in Aquinas''s theology — making Islamic philosophy a constitutive element of Catholic intellectual tradition.', 0.85, true),
('philosopher_al_ghazali', 'philosopher_averroes', 'responded_to', 'reason_vs_faith', 'Averroes''s The Incoherence of the Incoherence was a direct, systematic refutation of Al-Ghazali''s attack on philosophy. He defended Aristotle against every theological objection. But Al-Ghazali won the historical argument within the Islamic world — Islamic philosophy turned from Averroes and never recovered its rationalist tradition.', 1.0, true),
('philosopher_averroes', 'philosopher_aquinas', 'influenced', 'reason_vs_faith', 'Averroes''s commentaries on Aristotle were the vehicle through which Aristotle re-entered Western thought. Aquinas called him simply "The Commentator." The greatest synthesis of Christian theology — the Summa Theologica — is built on a foundation transmitted through Islamic philosophy. Without Averroes, no Aquinas.', 0.95, true),
('philosopher_al_ghazali', 'battle_reason_faith', 'applied_in', 'reason_vs_faith', 'Al-Ghazali''s victory over Islamic rationalism is one of history''s most consequential intellectual defeats. He demonstrated that Aristotelian philosophy contradicts Islamic theology on key points — and concluded that theology must win. The road not taken: an Islam that had followed Averroes instead of Al-Ghazali might have produced its own Enlightenment.', 0.9, true),

-- EAST-WEST TRANSMISSION
('event_alexander_conquests', 'philosopher_al_kindi', 'transmitted', null, 'The Greek intellectual tradition that Alexander''s conquests spread across the Persian world — preserved in Hellenistic cities like Alexandria — became the corpus that Islamic translators systematically converted to Arabic. Alexander''s cultural imperialism created the library that Islam preserved.', 0.7, true),
('philosopher_plotinus', 'philosopher_al_farabi', 'transmitted', 'reality_vs_mysticism', 'Neoplatonism reached the Islamic world through the Translation Movement — particularly the Theology of Aristotle (actually Plotinus''s Enneads misattributed to Aristotle). This created a profound Neoplatonic coloring in Islamic philosophy that shaped Al-Farabi, Avicenna, and Islamic mysticism (Sufism).', 0.75, true),
('philosopher_aristotle', 'philosopher_averroes', 'transmitted', 'reason_vs_faith', 'Aristotle''s complete works reached Averroes through Arabic translations, and Averroes returned them to Europe through Latin translations of his commentaries. This 1,500-year journey — Athens to Alexandria to Baghdad to Córdoba to Paris — is the most improbable transmission of knowledge in intellectual history.', 1.0, true),
('philosopher_confucius', 'philosopher_voltaire', 'transmitted', 'reason_vs_faith', 'Jesuit missionaries brought Confucian texts to Europe in the 17th century. Voltaire and Leibniz were fascinated — here was a civilization that had achieved social order, ethical culture, and civilized governance without Christianity. Voltaire cited China as proof that good society does not require revealed religion.', 0.7, true),
('philosopher_upanishads', 'philosopher_schopenhauer', 'transmitted', 'reality_vs_mysticism', 'Schopenhauer encountered the Upanishads through Anquetil-Duperron''s Latin translation (1801-2). His recognition was immediate and total: "In the whole world there is no study so beneficial and so elevating as that of the Upanishads. It has been the solace of my life — it will be the solace of my death."', 0.85, true),

-- MEDIEVAL WESTERN
('event_fall_rome', 'era_middle_ages', 'caused', null, 'The fall of Rome destroyed the institutional infrastructure of classical learning in Western Europe. Philosophy survived only in monasteries. The Church became the sole institution capable of sustaining intellectual life — subordinating reason to theological authority for a millennium.', 0.9, true),
('philosopher_augustine', 'philosopher_aquinas', 'influenced', 'reason_vs_faith', 'Aquinas built on Augustinian foundations — the synthesis of Platonic philosophy and Christian theology — but replaced Plato with Aristotle. Where Augustine was a Neoplatonist who became Christian, Aquinas was an Aristotelian who demonstrated that Aristotle and Christianity are compatible. The theological tradition runs continuously from Augustine through Aquinas.', 0.85, true),
('philosopher_ockham', 'event_scientific_revolution', 'influenced', 'reason_vs_faith', 'Ockham''s nominalism — universal concepts are merely names, not real things — eroded the Aristotelian-Thomistic synthesis. His insistence on empirical particulars over abstract universals pointed toward the scientific method: stop arguing about universals and examine the actual things.', 0.65, true),

-- RENAISSANCE AND SCIENTIFIC REVOLUTION
('event_printing_press', 'event_scientific_revolution', 'caused', 'reason_vs_faith', 'The printing press made it possible for Copernicus, Galileo, and Newton to build on each other''s work across distance and time. Scientific knowledge could accumulate and be critiqued publicly rather than remaining locked in manuscript copies. Ideas could outrun institutional suppression for the first time.', 0.9, true),
('event_printing_press', 'event_protestant_reformation', 'caused', 'reason_vs_faith', 'Luther''s 95 Theses spread across Germany in weeks — something impossible before printing. The Reformation was the first mass media event in history. The printing press transferred the power to interpret scripture from the Church hierarchy to the individual reader — the most consequential decentralization of knowledge before the internet.', 0.9, true),
('philosopher_bacon', 'event_scientific_revolution', 'influenced', 'reality_vs_mysticism', 'Bacon''s insistence on inductive reasoning from systematic observation — against Aristotelian deduction from first principles — provided the philosophical method the Scientific Revolution needed. He did not contribute scientific discoveries but the epistemological framework that organized them.', 0.8, true),
('philosopher_machiavelli', 'philosopher_hobbes', 'influenced', 'freedom_vs_coercion', 'Hobbes applied Machiavellian political realism systematically — human beings are selfish and competitive; political authority is justified not by virtue but by necessity. Machiavelli analyzed how power works; Hobbes explained why it is legitimate.', 0.75, true),
('event_protestant_reformation', 'philosopher_locke', 'influenced', 'freedom_vs_coercion', 'The Reformation established the principle of individual conscience against institutional authority — the right of each person to interpret scripture for themselves. Locke secularized this principle into natural rights and religious toleration. The Protestant insistence on individual judgment before God became the Lockean insistence on individual rights before the state.', 0.7, true),

-- ENLIGHTENMENT CHAIN
('event_scientific_revolution', 'era_enlightenment', 'caused', 'reason_vs_faith', 'The success of Newtonian physics in explaining the cosmos through mathematical laws inspired Enlightenment thinkers to apply the same rational method to society, morality, and politics. If nature obeys discoverable laws, why not human nature? The Scientific Revolution created the Enlightenment''s confidence in reason.', 0.95, true),
('philosopher_hobbes', 'philosopher_locke', 'responded_to', 'freedom_vs_coercion', 'Locke''s Second Treatise was a systematic answer to Hobbes. Against absolute sovereignty as the solution to the state of nature, Locke argued that individuals retain natural rights even under government — and have the right to revolt when government violates them. The foundational liberal response to the foundational statist argument.', 0.9, true),
('philosopher_locke', 'philosopher_rousseau', 'responded_to', 'individualism_vs_collectivism', 'Rousseau accepted Locke''s social contract framework but inverted its conclusion. Where Locke protected individual rights against the collective, Rousseau subordinated individual will to the general will. The two thinkers share a framework but produce opposite political philosophies: liberalism vs democratic collectivism.', 0.85, true),
('philosopher_locke', 'philosopher_montesquieu', 'influenced', 'freedom_vs_coercion', 'Montesquieu built on Lockean political philosophy — the need to constrain power — but approached it comparatively and institutionally rather than through natural rights. His separation of powers was the institutional mechanism for achieving what Locke demanded in principle: government that cannot tyrannize.', 0.8, true),
('philosopher_descartes', 'philosopher_hume', 'responded_to', 'reason_vs_faith', 'Hume''s radical empiricism was a direct assault on Cartesian rationalism. Where Descartes found certainty in pure reason, Hume argued our most basic beliefs — causation, personal identity, induction — rest on habit and sentiment, not reason. He destroyed the rationalist foundations that Descartes had built.', 0.9, true),
('philosopher_hume', 'philosopher_kant', 'influenced', 'reason_vs_faith', 'Kant said Hume "awakened him from his dogmatic slumber." Hume''s destruction of rationalist certainty forced Kant to ask: how is synthetic a priori knowledge possible at all? The Critique of Pure Reason was Kant''s answer — and the most ambitious philosophical system of the modern era.', 0.95, true),
('philosopher_locke', 'concept_natural_rights', 'derived_from', 'individualism_vs_collectivism', 'Locke''s Second Treatise grounded natural rights in reason and the nature of persons as self-owning agents. Life, liberty, and property are pre-political rights that government exists to protect, not grant. The foundational text of liberal individualism.', 0.95, true),
('philosopher_locke', 'event_american_revolution', 'influenced', 'freedom_vs_coercion', 'Jefferson''s Declaration of Independence is substantially a précis of Lockean political philosophy. "We hold these truths to be self-evident" — Locke''s natural rights in founding document form. The most successful application of philosophical principles to political construction in history.', 0.95, true),
('philosopher_rousseau', 'event_french_revolution', 'influenced', 'individualism_vs_collectivism', 'The revolutionaries read Rousseau''s Social Contract as their philosophical charter. The general will — the collective sovereign — justified the Terror: individual rights could be sacrificed to the will of the people as a whole. Burke and others identified Rousseau as the intellectual father of revolutionary violence.', 0.9, true),
('philosopher_smith', 'concept_free_market', 'derived_from', 'free_market_vs_planning', 'The Wealth of Nations demonstrated that voluntary exchange guided by price signals produces social prosperity without central direction. Smith''s invisible hand is the foundational philosophical argument for market economies over planned ones — later deepened by Hayek into an epistemological argument.', 0.95, true),
('philosopher_kant', 'concept_categorical_imperative', 'derived_from', 'individualism_vs_collectivism', 'Kant''s categorical imperative grounds morality in rational universalizability: act only on principles you could will everyone to follow. It demands treating persons as ends in themselves, never merely as means. The foundation of deontological ethics — and the ethics Rand most directly opposed with her virtue-of-selfishness argument.', 0.95, true),
('philosopher_burke', 'philosopher_hayek', 'influenced', 'freedom_vs_coercion', 'Burke''s argument that abstract rational principles applied to politics produce destruction anticipates Hayek''s argument that central planning is epistemically impossible. Both argue for the wisdom of evolved institutions over rationalist redesign — Burke from a traditionalist perspective, Hayek from an epistemological one.', 0.7, true),
('philosopher_wollstonecraft', 'philosopher_mill', 'influenced', 'individualism_vs_collectivism', 'Mill''s The Subjection of Women built directly on Wollstonecraft''s Vindication — applying consistent liberal principles to women''s condition. Both argued that if reason is the standard of human dignity and rights, there is no justification for excluding women from political and civil equality.', 0.75, true),

-- 19TH CENTURY
('philosopher_kant', 'philosopher_hegel', 'influenced', 'reality_vs_mysticism', 'Hegel began as a Kantian but found the thing-in-itself philosophically intolerable. If there is a reality beyond reason''s reach, philosophy is defeated. Hegel''s response: reality IS rational — the Absolute is Reason developing itself through history. The thing-in-itself dissolves into the dialectical process.', 0.85, true),
('philosopher_hegel', 'concept_dialectic', 'derived_from', 'good_vs_evil', 'Hegel''s dialectic — thesis generates antithesis, which resolves into synthesis — was his account of how ideas, history, and reality develop through contradiction toward higher truths. It simultaneously inspired Marxist historical materialism and fascist historical destiny. The most dangerous philosophical method in modern thought.', 0.9, true),
('philosopher_hegel', 'philosopher_marx', 'influenced', 'individualism_vs_collectivism', 'Marx was a Young Hegelian who "stood Hegel on his head" — keeping the dialectical structure but replacing idealist development with material class conflict. The communist revolution was to be the final Hegelian synthesis: the resolution of the contradiction between capital and labor into a classless society.', 0.95, true),
('philosopher_marx', 'concept_class_struggle', 'derived_from', 'individualism_vs_collectivism', 'Class struggle is Marx''s master key to history. All political, legal, religious, and philosophical forms are superstructure built on the economic base. Understanding history means understanding who owns the means of production — and recognizing that the struggle between classes drives all historical change.', 0.95, true),
('event_industrial_revolution_event', 'philosopher_marx', 'caused', 'free_market_vs_planning', 'Marx''s entire analysis was a response to industrialization. Without the factory system, wage labor, and capital concentration, there is no Marxist political economy. Industrialization created the conditions — the proletariat, the bourgeoisie, the alienation of labor — that Marx''s theory explains and his politics seeks to resolve.', 0.9, true),
('event_darwins_origin', 'philosopher_nietzsche', 'influenced', 'value_creation_vs_nihilism', 'Darwin removed purpose and design from biology — nature selects, it does not intend. Nietzsche radicalized this: if there is no cosmic purpose, then all values are human creations. The will to power — the drive to overcome and create — replaces divine or natural teleology as the source of value. The death of God follows Darwin''s death of design.', 0.8, true),
('philosopher_nietzsche', 'concept_will_to_power', 'derived_from', 'value_creation_vs_nihilism', 'The will to power is Nietzsche''s answer to nihilism. If God is dead and values are human creations, the question is not whether to create values but whether to create them consciously (the Übermensch) or resentfully (slave morality). Value creation — not acceptance — is the highest human achievement.', 0.9, true),
('philosopher_schopenhauer', 'philosopher_nietzsche', 'influenced', 'value_creation_vs_nihilism', 'Nietzsche began as a Schopenhauerian — accepting the pessimistic diagnosis that blind, purposeless Will underlies reality and produces suffering. He then radically rejected the conclusion: not resignation (Schopenhauer) or Buddhist extinguishing of desire, but life-affirmation and the creation of new values. Nietzsche is the anti-Schopenhauer.', 0.85, true),
('philosopher_kierkegaard', 'philosopher_heidegger', 'influenced', 'reason_vs_faith', 'Kierkegaard''s insistence on the irreducible individual subject — facing absolute choices without rational guidance — became Heidegger''s Dasein (being-there), the individual thrown into a world it did not choose. Both reject Hegelian impersonal rationalism for the concrete, anxious, existing individual.', 0.8, true),
('philosopher_marx', 'event_publication_communist_manifesto', 'caused', 'individualism_vs_collectivism', 'The Communist Manifesto was the distillation of Marx''s philosophical analysis into a political program. It transformed a philosophical argument about historical materialism into a revolutionary call to action — the most consequential single document in modern political history.', 0.95, true),

-- 20TH CENTURY
('event_publication_communist_manifesto', 'event_russian_revolution', 'caused', 'individualism_vs_collectivism', 'Lenin''s Bolsheviks explicitly identified themselves as the vanguard party called for in the Communist Manifesto. The Russian Revolution was the first attempt to implement Marx''s vision — 69 years after the Manifesto predicted its imminent arrival.', 0.85, true),
('philosopher_marx', 'event_russian_revolution', 'applied_in', 'free_market_vs_planning', 'The Russian Revolution was the most consequential application of Marxist theory in history. Lenin adapted Marx''s proletarian revolution to an agrarian society, creating the party-state model that became the template for communist movements worldwide. The 70-year Soviet experiment was Marxist economics in practice.', 0.9, true),
('event_ww1', 'event_russian_revolution', 'caused', 'freedom_vs_coercion', 'WWI''s catastrophic losses destroyed the legitimacy of the Tsar. The Bolsheviks promised peace, land, and bread to a society exhausted by a war its government could neither win nor end. The Revolution was Marx''s theory meeting Tolstoy''s pacifism in the ruins of a military catastrophe.', 0.9, true),
('event_ww1', 'event_rise_nazism', 'caused', 'good_vs_evil', 'The Versailles Treaty''s humiliation of Germany — war guilt, reparations, territorial losses — created the resentment Hitler exploited. His political program was a promise to reverse WWI''s outcome. Every element of Nazism — the stab-in-the-back myth, the master race ideology, the need for Lebensraum — was a response to the trauma of military defeat and national humiliation.', 0.9, true),
('philosopher_nietzsche', 'event_rise_nazism', 'responded_to', 'good_vs_evil', 'The Nazis systematically distorted Nietzsche''s philosophy — with the complicity of his antisemitic sister Elisabeth Förster-Nietzsche — to provide intellectual legitimacy for racial ideology. Nietzsche explicitly condemned German nationalism, antisemitism, and the state. The distortion was deliberate and catastrophic: the philosopher of individual excellence misread as the prophet of racial domination.', 0.85, true),
('event_rise_nazism', 'event_ww2', 'caused', 'good_vs_evil', 'WWII was not an accident but the logical outcome of Nazi ideology applied to power. Lebensraum required conquest. Racial hierarchy required extermination. The destruction of the Versailles order required war. Nazi philosophy made WWII inevitable once Nazi politics gained state power.', 0.95, true),
('event_ww2', 'event_holocaust', 'caused', 'good_vs_evil', 'The Holocaust was not a byproduct of WWII but a parallel deliberate operation. Resources were diverted from the war effort to maintain the death camps as Germany''s military position deteriorated. Genocide was the purpose; war was the enabling condition. Industrialized evil is not a byproduct of war — it is a choice.', 0.95, true),
('philosopher_popper', 'concept_falsifiability', 'derived_from', 'reason_vs_faith', 'Popper''s falsifiability criterion emerged from his dissatisfaction with Marxism and psychoanalysis — theories that could explain everything and therefore tested nothing. Science advances by bold conjectures and genuine attempts at refutation. Unfalsifiable theories are not wrong — they are not science.', 0.95, true),
('philosopher_popper', 'concept_open_society', 'derived_from', 'freedom_vs_coercion', 'Popper''s Open Society was written while fleeing Nazi Europe — a philosopher''s response to totalitarianism. The open society is defined by its tolerance for criticism and its ability to change institutions without violence. Closed societies — Platonic, Marxist, fascist — derive their authority from historical destiny or ideological certainty.', 0.9, true),
('philosopher_hayek', 'concept_spontaneous_order', 'derived_from', 'free_market_vs_planning', 'Hayek''s spontaneous order insight demolished the intellectual case for central planning. No authority can possess the distributed, local, tacit knowledge that price systems process automatically. Central planning is not merely inefficient — it is epistemically impossible. The Road to Serfdom showed that the attempt produces tyranny regardless of intent.', 0.95, true),
('philosopher_arendt', 'event_holocaust', 'responded_to', 'good_vs_evil', 'Arendt''s Origins of Totalitarianism and Eichmann in Jerusalem were philosophical responses to the Holocaust. Her concept of the "banality of evil" — bureaucratic thoughtlessness as the vehicle for genocide — challenged the comfortable assumption that evil requires monsters. Ordinary people, following orders, can produce extraordinary evil.', 0.9, true),
('philosopher_rawls', 'concept_veil_of_ignorance', 'derived_from', 'individualism_vs_collectivism', 'The veil of ignorance operationalizes Kantian impartiality into a decision procedure for justice. Rational agents designing society without knowing their position would choose principles protecting the worst-off — because they might be the worst-off. It is the most influential argument for redistributive justice in 20th century political philosophy.', 0.95, true),
('philosopher_kant', 'philosopher_rawls', 'influenced', 'individualism_vs_collectivism', 'Rawls explicitly identified his project as neo-Kantian — grounding justice in what rational agents would choose under conditions of impartiality. The categorical imperative''s universalizability becomes the veil of ignorance. Rawls is the 20th century''s most consequential Kantian.', 0.85, true),
('philosopher_foucault', 'concept_totalitarianism', 'responded_to', 'freedom_vs_coercion', 'Foucault analyzed how power operates through knowledge, normalization, and discipline — not only in totalitarian systems but in liberal democracies through prisons, hospitals, and schools. His work challenged the comfortable distinction between free and unfree societies: discipline is everywhere, not only where it is visible.', 0.75, true),
('philosopher_sartre', 'event_cold_war', 'applied_in', 'individualism_vs_collectivism', 'Sartre''s tortured relationship with Soviet communism — defending atrocities he privately condemned while insisting on absolute individual freedom — exemplifies the moral catastrophe of 20th century left-wing intellectualism. His bad faith about Soviet reality was the philosophical failure of a generation.', 0.65, true),
('event_cold_war', 'event_fall_berlin_wall', 'caused', 'free_market_vs_planning', 'The Cold War was the 70-year competition between free market capitalism and central planning. The fall of the Berlin Wall was the empirical verdict: central planning cannot produce prosperity, freedom, or legitimacy. Hayek''s epistemological argument was confirmed by history.', 0.9, true),

-- AYN RAND CONNECTIONS
('philosopher_aristotle', 'philosopher_rand', 'influenced', 'reality_vs_mysticism', 'Rand identified Aristotle as the greatest philosopher in history and her primary philosophical ancestor. His metaphysical realism — reality exists independent of consciousness, and reason is the means of grasping it — is the foundation of Objectivism. She dedicated Atlas Shrugged to Aristotle and her husband, and traced every element of Objectivist metaphysics and epistemology to Aristotelian roots.', 1.0, true),
('philosopher_rand', 'concept_objectivism', 'derived_from', null, 'Objectivism is Rand''s integrated philosophical system, developed across The Fountainhead (1943), Atlas Shrugged (1957), and her non-fiction essays collected in The Virtue of Selfishness, Capitalism: The Unknown Ideal, and Introduction to Objectivist Epistemology. Each branch — metaphysics, epistemology, ethics, politics, aesthetics — is derived from its predecessors by reason.', 1.0, true),
('philosopher_rand', 'concept_rational_self_interest', 'derived_from', 'good_vs_evil', 'Rand''s ethics of rational self-interest was her most controversial contribution. The Virtue of Selfishness (1964) argued that altruism — the moral code demanding self-sacrifice — is not virtuous but destructive: it subordinates the individual''s life to others and makes productive achievement morally impossible. Rational self-interest is not exploitation but the full realization of one''s human potential through productive work and chosen values.', 0.95, true),
('philosopher_rand', 'concept_free_market', 'derived_from', 'free_market_vs_planning', 'Rand defended capitalism not on utilitarian grounds — that it produces prosperity — but on moral grounds: it is the only system consistent with individual rights. Capitalism: The Unknown Ideal (1966) argued that every form of government intervention in economics violates individual rights. She offered the most principled philosophical defense of laissez-faire capitalism in the 20th century.', 0.95, true),
('philosopher_rand', 'concept_objectivism', 'applied_in', 'beauty_vs_chaos', 'Rand developed an Objectivist aesthetics in The Romantic Manifesto (1969). Art must present a moral ideal through concrete sensory form. Romantic art — selective re-creation of reality according to the artist''s values — is superior to Naturalism''s photographic reproduction of randomness. Beauty is not subjective: it is the sensory form of values, and values are objectively knowable.', 0.85, true),
('philosopher_kant', 'philosopher_rand', 'opposes_legacy_of', 'reason_vs_faith', 'Rand identified Kant as the most destructive philosopher in Western history — the philosopher she opposed above all others. His thing-in-itself placed ultimate reality beyond reason''s reach, rehabilitating faith and mysticism in modern dress. His categorical imperative demanded duty to abstract universal law rather than individual life and happiness. She called him the first systematic philosopher of the primacy of consciousness over existence.', 0.95, true),
('philosopher_nietzsche', 'philosopher_rand', 'influenced', 'value_creation_vs_nihilism', 'Rand read Nietzsche as a teenager in Russia and was initially drawn to his celebration of individual greatness and attack on slave morality. She later rejected him decisively for lacking a rational foundation — Nietzsche''s will to power is emotional and instinctual, not rational. Her heroes share Nietzsche''s contempt for mediocrity but are grounded in reason and productive achievement, not instinct and domination.', 0.75, true),
('philosopher_marx', 'philosopher_rand', 'opposes_legacy_of', 'individualism_vs_collectivism', 'Rand identified Marxism as the philosophical embodiment of everything Objectivism opposes: the primacy of the collective over the individual, the moral legitimacy of expropriating individual achievement, and the grounding of ethics in need (each according to his need) rather than production. Atlas Shrugged is explicitly a philosophical answer to Marxist collectivism.', 0.9, true),
('philosopher_locke', 'philosopher_rand', 'influenced', 'freedom_vs_coercion', 'Rand built on Lockean natural rights but gave them a deeper philosophical foundation in human nature and the requirements of human survival as a rational being. Rights are not natural law or divine grant but recognition of the conditions necessary for individual human life. She acknowledged Locke as a major contributor to the political philosophy she defended.', 0.7, true),
('event_russian_revolution', 'philosopher_rand', 'caused', 'individualism_vs_collectivism', 'Rand was born in St. Petersburg in 1905 and witnessed the Bolshevik Revolution firsthand. Her father''s pharmacy was confiscated by the Soviet state. She escaped to America in 1926. The Soviet experience was not abstract to her — it was the direct personal context that transformed her philosophical opposition to collectivism from an intellectual position into a life-defining mission.', 0.9, true),
('philosopher_rand', 'event_cold_war', 'applied_in', 'free_market_vs_planning', 'Rand''s ideas became a significant intellectual current in American conservative and libertarian thought during the Cold War. Atlas Shrugged (1957) was read as the philosophical defense of capitalism against Soviet collectivism. Her influence on Alan Greenspan''s Federal Reserve philosophy and Reagan-era economic policy gave Objectivism direct political application.', 0.75, true),
('philosopher_hayek', 'philosopher_rand', 'responded_to', 'free_market_vs_planning', 'Rand and Hayek reached similar political conclusions — capitalism, individual freedom, opposition to central planning — from different philosophical foundations. Hayek grounded his defense in epistemology (distributed knowledge) and evolutionary tradition. Rand grounded hers in individual rights and rational ethics. She criticized The Road to Serfdom for defending freedom on utilitarian rather than moral grounds — a criticism she considered philosophically fundamental.', 0.7, true),
('philosopher_rand', 'philosopher_rawls', 'opposes_legacy_of', 'individualism_vs_collectivism', 'Rawls''s veil of ignorance produces principles protecting the worst-off — redistributing from productive achievement to need. Rand identified this as the philosophical institutionalization of need as a moral claim against producers. A just society protects individual rights and productive achievement regardless of outcome distribution — not because the outcome is equal but because the process is free.', 0.85, true),
('philosopher_rand', 'battle_individual_collective', 'derived_from', 'individualism_vs_collectivism', 'Rand is the 20th century''s most uncompromising philosophical defender of the individual against the collective. Her entire system — metaphysics, epistemology, ethics, politics, aesthetics — is organized around the primacy of the individual: individual consciousness, individual reason, individual values, individual rights.', 0.9, true),

-- BATTLE DIMENSION CONNECTIONS
('philosopher_heraclitus', 'battle_reality_mysticism', 'derived_from', 'reality_vs_mysticism', 'Heraclitus established the rational order (Logos) as the principle underlying apparent flux and contradiction. His insistence that the cosmos is governed by a rational principle accessible to human reason — against mythological explanation — marks the beginning of the reason-vs-mysticism battle in Western thought.', 0.8, true),
('philosopher_plato', 'battle_reality_mysticism', 'applied_in', 'reality_vs_mysticism', 'Plato''s theory of Forms is the most sophisticated philosophical defense of the mystical position: ultimate reality is not accessible through the senses but only through rational intuition of abstract, eternal, perfect Forms. The physical world is shadow and appearance. This is mysticism with philosophical rigor.', 0.85, true),
('philosopher_kant', 'battle_reason_faith', 'applied_in', 'reason_vs_faith', 'Kant is the pivotal figure in the reason-vs-faith battle: his critique of reason''s limits — the thing-in-itself beyond cognition — simultaneously demolished traditional metaphysics and created philosophical space for faith. His religion within the limits of reason alone attempted a middle path that satisfied neither rationalists nor theologians.', 0.9, true),
('philosopher_marx', 'battle_individual_collective', 'applied_in', 'individualism_vs_collectivism', 'Marx''s system is the most consequential philosophical argument for the primacy of the collective in modern history. The individual is not a sovereign subject but a product of class position and historical forces. Individual consciousness is false consciousness — the ideological expression of class interest.', 0.95, true),
('philosopher_locke', 'battle_freedom_coercion', 'derived_from', 'freedom_vs_coercion', 'Locke established the philosophical framework of the freedom-vs-coercion battle: individuals have natural rights that pre-exist and constrain political authority. Government is legitimate only when it protects these rights — and may be resisted when it violates them. Every subsequent debate about the scope of state power is conducted in Lockean terms.', 0.9, true),
('philosopher_nietzsche', 'battle_creation_nihilism', 'derived_from', 'value_creation_vs_nihilism', 'Nietzsche is the central figure in the value-creation-vs-nihilism battle. He identified the problem (God is dead, values have no cosmic foundation) and attempted a solution (the will to power creates new values). But his solution lacks rational grounding — which is why Rand considered him the nearest thing to a precursor and simultaneously inadequate.', 0.9, true),
('philosopher_smith', 'battle_market_planning', 'derived_from', 'free_market_vs_planning', 'Smith established the philosophical case for free markets as the central question of modern economic and political philosophy. Every subsequent debate — Ricardo vs Malthus, Marx vs Mill, Keynes vs Hayek, Rawls vs Nozick — is an elaboration of the question Smith first posed: can voluntary exchange produce social order?', 0.9, true),
('philosopher_aristotle', 'battle_beauty_chaos', 'derived_from', 'beauty_vs_chaos', 'Aristotle''s Poetics established the terms of the beauty-vs-chaos battle in aesthetics: art imitates nature and produces catharsis through ordered, purposeful form. His concept of mimesis — art as selective imitation of reality according to the probable and necessary — anticipates Rand''s Romantic aesthetics by 2,300 years.', 0.8, true),
('philosopher_plato', 'battle_good_evil', 'derived_from', 'good_vs_evil', 'Plato''s Republic is the foundational text of the good-vs-evil battle in political philosophy: justice is the health of the soul and the city; injustice is disease. The philosopher-king knows the Good through rational intuition of the Form of the Good. Plato made the battle between good governance and tyranny a question of philosophical knowledge.', 0.85, true),

-- CONTEMPORARY
('event_fall_berlin_wall', 'era_contemporary', 'caused', 'free_market_vs_planning', 'The fall of the Berlin Wall ended the Cold War and appeared to confirm liberal democracy as the final form of political organization. It set the conditions for globalization, the internet revolution, and the subsequent nationalist backlash — beginning the contemporary era''s unresolved political crisis.', 0.85, true),
('event_2008_financial_crisis', 'concept_free_market', 'responded_to', 'free_market_vs_planning', 'The 2008 crisis revived dormant debates about market stability and regulation. Critics argued it demonstrated the catastrophic risks of unregulated finance. Defenders argued it demonstrated the consequences of government distortion of housing markets. The philosophical debate about capitalism''s viability — settled in 1989 — re-opened.', 0.75, true),
('event_ai_revolution', 'concept_reason', 'responded_to', 'reality_vs_mysticism', 'Artificial intelligence forces philosophy to revisit fundamental questions about consciousness, creativity, and intelligence itself. If machines can reason, what is distinctive about human reason? If language models can produce philosophical arguments, what is philosophy? The Axial Age questions about the nature of mind return in technological form.', 0.8, true),
('event_september_11', 'battle_reason_faith', 'applied_in', 'reason_vs_faith', 'The September 11 attacks forced a reckoning with the relationship between religion, violence, and political philosophy. They demonstrated that the reason-vs-faith battle is not merely academic — when faith sanctions violence and promises paradise, it produces catastrophic real-world consequences. The Enlightenment''s confidence that reason would eventually prevail over religious fanaticism was challenged.', 0.75, true)
